  8→@MainActor
  9→final class AuthenticationStore: ObservableObject {
 10→    private enum Keys {
 11→        static let currentUser = "auth.currentUser"
 12→        static let appleIdentityCache = "auth.appleIdentityCache"
 13→        static let emailRegistry = "auth.emailRegistry"
 14→        static let appleRefreshToken = "apple.refresh_token"
 15→    }
 16→
 17→    @Published private(set) var currentUser: AuthSessionUser?
 18→    @Published private(set) var isBusy = false
 19→    @Published var lastErrorMessage: String?
 20→
 21→    private var hasRestoredSession = false
 22→    private var emailRegistry: AuthEmailRegistry
 23→    private let defaults: UserDefaults
 24→    private let decoder = JSONDecoder()
 25→    private let encoder = JSONEncoder()
 26→
 27→    init(defaults: UserDefaults = .standard) {
 28→        self.defaults = defaults
 29→        self.currentUser = Self.loadCurrentUser(from: defaults)
 30→        self.emailRegistry = Self.loadEmailRegistry(from: defaults)
 31→
 32→        if let currentUser {
 33→            _ = registerEmailIfNeeded(for: currentUser)
 34→        }
 35→    }
 36→
 37→    func restoreSessionIfNeeded() async {
 38→        guard hasRestoredSession == false else {
 39→            return
 40→        }
 41→        hasRestoredSession = true
 42→
 43→        guard GIDSignIn.sharedInstance.hasPreviousSignIn() else {
 44→            return
 45→        }
 46→
 47→        do {
 48→            let googleUser = try await GIDSignIn.sharedInstance.restorePreviousSignIn()
 49→            let sessionUser = makeGoogleSessionUser(from: googleUser)
 50→            if applySignedInCandidate(sessionUser) == false {
 51→                GIDSignIn.sharedInstance.signOut()
 52→            }
 53→        } catch {
 54→            GIDSignIn.sharedInstance.signOut()
 55→            if currentUser?.provider == .google {
 56→                applySignedInUser(nil)
 57→            }
 58→        }
 59→    }
 60→
 61→    func signInWithGoogle(presenting presentingViewController: UIViewController) async {
 62→        lastErrorMessage = nil
 63→
 64→        guard let configuration = googleConfigurationValues else {
 65→            lastErrorMessage = String(localized: "auth.error.google_client_id_missing")
 66→            return
 67→        }
 68→
 69→        guard ensureGoogleURLSchemeRegistered(for: configuration) else {
 70→            return
 71→        }
 72→
 73→        isBusy = true
 74→        defer { isBusy = false }
 75→
 76→        do {
 77→            GIDSignIn.sharedInstance.configuration = GIDConfiguration(clientID: configuration.clientID)
 78→            let signInResult = try await GIDSignIn.sharedInstance.signIn(withPresenting: presentingViewController)
 79→            let sessionUser = makeGoogleSessionUser(from: signInResult.user)
 80→            if applySignedInCandidate(sessionUser) == false {
 81→                GIDSignIn.sharedInstance.signOut()
 82→            }
 83→        } catch {
 84→            if Self.isUserCancellation(error) {
 85→                return
 86→            }
 87→            lastErrorMessage = String(localized: "auth.error.google_sign_in_failed")
 88→        }
 89→    }
 90→
 91→    func handleAppleSignInResult(_ result: Result<ASAuthorization, Error>) {
 92→        lastErrorMessage = nil
 93→
 94→        switch result {
 95→        case .success(let authorization):
 96→            guard let credential = authorization.credential as? ASAuthorizationAppleIDCredential else {
 97→                lastErrorMessage = String(localized: "auth.error.apple_sign_in_failed")
 98→                return
 99→            }
100→            let sessionUser = makeAppleSessionUser(from: credential)
101→            guard applySignedInCandidate(sessionUser) else { return }
102→
103→            if let authCode = credential.authorizationCode,
104→               let codeString = String(data: authCode, encoding: .utf8) {
105→                Task {
106→                    await exchangeAppleAuthorizationCode(codeString)
107→                }
108→            }
109→        case .failure(let error):
110→            if Self.isUserCancellation(error) {
111→                return
112→            }
113→            lastErrorMessage = String(localized: "auth.error.apple_sign_in_failed")
114→        }
115→    }
116→
117→    func handleOpenURL(_ url: URL) {
118→        _ = GIDSignIn.sharedInstance.handle(url)
119→    }
120→
121→    func signOut() {
122→        if currentUser?.provider == .google {
123→            GIDSignIn.sharedInstance.signOut()
124→        }
125→        applySignedInUser(nil)
126→    }
127→
128→    func deleteAccount(modelContext: ModelContext, settings: AppSettings) async {
129→        if currentUser?.provider == .google {
130→            do {
131→                try await GIDSignIn.sharedInstance.disconnect()
132→            } catch {
133→                print("[AuthenticationStore] Google disconnect failed: \(error)")
134→            }
135→            GIDSignIn.sharedInstance.signOut()
136→        }
137→
138→        if currentUser?.provider == .apple {
139→            await revokeAppleToken()
140→        }
141→
142→        do {
143→            try modelContext.delete(model: Subscription.self)
144→            try modelContext.save()
145→        } catch {
146→            lastErrorMessage = String(localized: "auth.error.delete_account_data_failed")
147→            return
148→        }
149→
150→        defaults.removeObject(forKey: Keys.currentUser)
151→        defaults.removeObject(forKey: Keys.appleIdentityCache)
152→        defaults.removeObject(forKey: Keys.emailRegistry)
153→        defaults.removeObject(forKey: "exchange_rate.snapshot.v1")
154→        defaults.removeObject(forKey: "service_catalog.payload.v1")
155→
156→        settings.resetToDefaults()
157→        emailRegistry = AuthEmailRegistry()
158→        applySignedInUser(nil)
159→    }
