161→    private var googleConfigurationValues: GoogleConfigurationValues? {
162→        let serviceValues = googleConfigurationFromServicePlist()
163→        guard let clientID = infoStringValue(forKey: "GOOGLE_CLIENT_ID") ?? serviceValues?.clientID else {
164→            return nil
165→        }
166→
167→        let reversedClientID = infoStringValue(forKey: "GOOGLE_REVERSED_CLIENT_ID")
168→            ?? serviceValues?.reversedClientID
169→
170→        return GoogleConfigurationValues(clientID: clientID, reversedClientID: reversedClientID)
171→    }
172→
173→    private func ensureGoogleURLSchemeRegistered(for configuration: GoogleConfigurationValues) -> Bool {
174→        guard let reversedClientID = configuration.reversedClientID else {
175→            lastErrorMessage = String(localized: "auth.error.google_reversed_client_id_missing")
176→            return false
177→        }
178→
179→        guard isURLSchemeRegistered(reversedClientID) else {
180→            lastErrorMessage = String(localized: "auth.error.google_url_scheme_missing")
181→            return false
182→        }
183→
184→        return true
185→    }
186→
187→    private func isURLSchemeRegistered(_ scheme: String) -> Bool {
188→        guard let urlTypes = Bundle.main.object(forInfoDictionaryKey: "CFBundleURLTypes") as? [[String: Any]] else {
189→            return false
190→        }
191→
192→        for urlType in urlTypes {
193→            guard let schemes = urlType["CFBundleURLSchemes"] as? [String] else {
194→                continue
195→            }
196→
197→            if schemes.contains(where: { $0.caseInsensitiveCompare(scheme) == .orderedSame }) {
198→                return true
199→            }
200→        }
201→
202→        return false
203→    }
204→
205→    private func infoStringValue(forKey key: String) -> String? {
206→        guard let rawValue = Bundle.main.object(forInfoDictionaryKey: key) as? String else {
207→            return nil
208→        }
209→        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
210→        return trimmed.isEmpty ? nil : trimmed
211→    }
212→
213→    private func googleConfigurationFromServicePlist() -> GoogleConfigurationValues? {
214→        guard let path = Bundle.main.path(forResource: "GoogleService-Info", ofType: "plist"),
215→              let dictionary = NSDictionary(contentsOfFile: path) as? [String: Any] else {
216→            return nil
217→        }
218→
219→        guard let clientIDRaw = dictionary["CLIENT_ID"] as? String else {
220→            return nil
221→        }
222→
223→        let clientID = clientIDRaw.trimmingCharacters(in: .whitespacesAndNewlines)
224→        guard clientID.isEmpty == false else {
225→            return nil
226→        }
227→
228→        let reversedClientID = (dictionary["REVERSED_CLIENT_ID"] as? String)?
229→            .trimmingCharacters(in: .whitespacesAndNewlines)
230→
231→        return GoogleConfigurationValues(
232→            clientID: clientID,
233→            reversedClientID: reversedClientID?.isEmpty == true ? nil : reversedClientID
234→        )
235→    }
