237→    @discardableResult
238→    private func applySignedInCandidate(_ user: AuthSessionUser) -> Bool {
239→        switch registerEmailIfNeeded(for: user) {
240→        case .success:
241→            applySignedInUser(user)
242→            return true
243→        case .failure:
244→            lastErrorMessage = String(localized: "auth.error.email_already_registered")
245→            return false
246→        }
247→    }
248→
249→    private func registerEmailIfNeeded(for user: AuthSessionUser) -> Result<Void, AuthEmailConflict> {
250→        let result = emailRegistry.register(
251→            email: user.email,
252→            userID: user.id,
253→            provider: user.provider
254→        )
255→
256→        if case .success = result {
257→            persistEmailRegistry(emailRegistry)
258→        }
259→
260→        return result
261→    }
262→
263→    private func applySignedInUser(_ user: AuthSessionUser?) {
264→        currentUser = user
265→        persistCurrentUser(user)
266→    }
267→
268→    private func persistCurrentUser(_ user: AuthSessionUser?) {
269→        guard let user else {
270→            defaults.removeObject(forKey: Keys.currentUser)
271→            return
272→        }
273→        guard let data = try? encoder.encode(user) else {
274→            return
275→        }
276→        defaults.set(data, forKey: Keys.currentUser)
277→    }
278→
279→    private static func loadCurrentUser(from defaults: UserDefaults) -> AuthSessionUser? {
280→        guard let data = defaults.data(forKey: Keys.currentUser) else {
281→            return nil
282→        }
283→        return try? JSONDecoder().decode(AuthSessionUser.self, from: data)
284→    }
285→
286→    private static func loadEmailRegistry(from defaults: UserDefaults) -> AuthEmailRegistry {
287→        guard let data = defaults.data(forKey: Keys.emailRegistry),
288→              let registry = try? JSONDecoder().decode(AuthEmailRegistry.self, from: data) else {
289→            return AuthEmailRegistry()
290→        }
291→        return registry
292→    }
