294→    private func makeAppleSessionUser(from credential: ASAuthorizationAppleIDCredential) -> AuthSessionUser {
295→        let userID = credential.user
296→        var cache = loadAppleIdentityCache()
297→        var identity = cache[userID] ?? AppleIdentityCache(displayName: nil, email: nil)
298→        let tokenClaims = credential.identityToken.flatMap(Self.decodeAppleIdentityTokenClaims)
299→
300→        if let displayName = Self.displayName(from: credential.fullName) {
301→            identity.displayName = displayName
302→        }
303→        if let displayName = Self.normalizedDisplayName(tokenClaims?.name) {
304→            identity.displayName = displayName
305→        }
306→        if let email = Self.normalizedEmail(credential.email) {
307→            identity.email = email
308→        }
309→        if let email = Self.normalizedEmail(tokenClaims?.email) {
310→            identity.email = email
311→        }
312→
313→        cache[userID] = identity
314→        persistAppleIdentityCache(cache)
315→
316→        return AuthSessionUser(
317→            id: userID,
318→            provider: .apple,
319→            displayName: identity.displayName ?? identity.email ?? String(localized: "auth.default_display_name"),
320→            email: identity.email
321→        )
322→    }
323→
324→    private func makeGoogleSessionUser(from user: GIDGoogleUser) -> AuthSessionUser {
325→        let fallbackID = user.profile?.email ?? UUID().uuidString
326→        let userID = user.userID ?? fallbackID
327→        let displayName = user.profile?.name
328→            ?? user.profile?.email
329→            ?? String(localized: "auth.default_display_name")
330→        let email = user.profile?.email
331→
332→        return AuthSessionUser(
333→            id: userID,
334→            provider: .google,
335→            displayName: displayName,
336→            email: email
337→        )
338→    }
