340→    private func loadAppleIdentityCache() -> [String: AppleIdentityCache] {
341→        guard let data = defaults.data(forKey: Keys.appleIdentityCache) else {
342→            return [:]
343→        }
344→        return (try? decoder.decode([String: AppleIdentityCache].self, from: data)) ?? [:]
345→    }
346→
347→    private func persistAppleIdentityCache(_ cache: [String: AppleIdentityCache]) {
348→        guard let data = try? encoder.encode(cache) else {
349→            return
350→        }
351→        defaults.set(data, forKey: Keys.appleIdentityCache)
352→    }
