361→    private static func displayName(from components: PersonNameComponents?) -> String? {
362→        guard let components else {
363→            return nil
364→        }
365→        let formatter = PersonNameComponentsFormatter()
366→        let value = formatter.string(from: components).trimmingCharacters(in: .whitespacesAndNewlines)
367→        return value.isEmpty ? nil : value
368→    }
