370→    private static func normalizedEmail(_ value: String?) -> String? {
371→        guard let value else {
372→            return nil
373→        }
374→        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
375→        return trimmed.isEmpty ? nil : trimmed
376→    }
