378→    private static func normalizedDisplayName(_ value: String?) -> String? {
379→        guard let value else {
380→            return nil
381→        }
382→        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
383→        return trimmed.isEmpty ? nil : trimmed
384→    }
