386→    private static func decodeAppleIdentityTokenClaims(from tokenData: Data) -> AppleIdentityTokenClaims? {
387→        guard let token = String(data: tokenData, encoding: .utf8) else {
388→            return nil
389→        }
390→
391→        let parts = token.split(separator: ".")
392→        guard parts.count >= 2 else {
393→            return nil
394→        }
395→
396→        var payload = String(parts[1])
397→            .replacingOccurrences(of: "-", with: "+")
398→            .replacingOccurrences(of: "_", with: "/")
399→
400→        let remainder = payload.count % 4
401→        if remainder == 2 {
402→            payload += "=="
403→        } else if remainder == 3 {
404→            payload += "="
405→        } else if remainder == 1 {
406→            return nil
407→        }
408→
409→        guard let payloadData = Data(base64Encoded: payload) else {
410→            return nil
411→        }
412→
413→        return try? JSONDecoder().decode(AppleIdentityTokenClaims.self, from: payloadData)
414→    }
415→
416→    private static func isUserCancellation(_ error: Error) -> Bool {
417→        let nsError = error as NSError
418→        if nsError.domain == ASAuthorizationError.errorDomain,
419→           nsError.code == ASAuthorizationError.canceled.rawValue {
420→            return true
421→        }
422→        return nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled
423→    }
