425→    // MARK: - Apple Token Helpers
426→
427→    private func exchangeAppleAuthorizationCode(_ code: String) async {
428→        guard let clientSecret = makeAppleClientSecret() else { return }
429→
430→        let bundleID = Bundle.main.bundleIdentifier ?? "com.uechikohei.subskun"
431→        do {
432→            let refreshToken = try await AppleTokenService.exchangeAuthorizationCode(
433→                code,
434→                clientID: bundleID,
435→                clientSecret: clientSecret
436→            )
437→            if let tokenData = refreshToken.data(using: .utf8) {
438→                KeychainHelper.save(key: Keys.appleRefreshToken, data: tokenData)
439→            }
440→        } catch {
441→            print("[AuthenticationStore] Apple auth code exchange failed: \(error)")
442→        }
443→    }
444→
445→    private func revokeAppleToken() async {
446→        guard let tokenData = KeychainHelper.read(key: Keys.appleRefreshToken),
447→              let refreshToken = String(data: tokenData, encoding: .utf8) else {
448→            return
449→        }
450→
451→        guard let clientSecret = makeAppleClientSecret() else {
452→            KeychainHelper.delete(key: Keys.appleRefreshToken)
453→            return
454→        }
455→
456→        let bundleID = Bundle.main.bundleIdentifier ?? "com.uechikohei.subskun"
457→        do {
458→            try await AppleTokenService.revokeToken(
459→                refreshToken: refreshToken,
460→                clientID: bundleID,
461→                clientSecret: clientSecret
462→            )
463→        } catch {
464→            print("[AuthenticationStore] Apple token revocation failed: \(error)")
465→        }
466→
467→        KeychainHelper.delete(key: Keys.appleRefreshToken)
468→    }
469→
470→    private func makeAppleClientSecret() -> String? {
471→        guard let keyID = infoStringValue(forKey: "APPLE_KEY_ID") else {
472→            return nil
473→        }
474→
475→        guard let p8Path = Bundle.main.path(forResource: "AuthKey", ofType: "p8"),
476→              let p8Data = FileManager.default.contents(atPath: p8Path),
477→              let p8String = String(data: p8Data, encoding: .utf8) else {
478→            return nil
479→        }
480→
481→        guard let privateKey = try? P256.Signing.PrivateKey(pemRepresentation: p8String) else {
482→            return nil
483→        }
484→
485→        let teamID = "SW4S6FR5L9"
486→        let bundleID = Bundle.main.bundleIdentifier ?? "com.uechikohei.subskun"
487→
488→        return try? AppleTokenService.makeClientSecret(
489→            teamID: teamID,
490→            keyID: keyID,
491→            bundleID: bundleID,
492→            privateKey: privateKey
493→        )
494→    }
495→}
