 68→final class AppSettings: ObservableObject {
 69→    private enum Keys {
 70→        static let defaultCurrency = "settings.defaultCurrency"
 71→        static let pastMonths = "settings.historyPastMonths"
 72→        static let futureMonths = "settings.historyFutureMonths"
 73→        static let includePausedInSummary = "settings.includePausedInSummary"
 74→        static let themeMode = "settings.themeMode"
 75→        static let themeColor = "settings.themeColor"
 76→        static let notifyBeforeBilling = "settings.notifyBeforeBilling"
 77→    }
 78→
 79→    @Published var defaultCurrency: String {
 80→        didSet {
 81→            let normalized = Self.normalizeCurrency(defaultCurrency)
 82→            if normalized != defaultCurrency {
 83→                defaultCurrency = normalized
 84→                return
 85→            }
 86→            defaults.set(normalized, forKey: Keys.defaultCurrency)
 87→        }
 88→    }
 89→
 90→    @Published var pastMonths: Int {
 91→        didSet {
 92→            let clamped = max(1, min(24, pastMonths))
 93→            if clamped != pastMonths {
 94→                pastMonths = clamped
 95→                return
 96→            }
 97→            defaults.set(clamped, forKey: Keys.pastMonths)
 98→        }
 99→    }
100→
101→    @Published var futureMonths: Int {
102→        didSet {
103→            let clamped = max(1, min(36, futureMonths))
104→            if clamped != futureMonths {
105→                futureMonths = clamped
106→                return
107→            }
108→            defaults.set(clamped, forKey: Keys.futureMonths)
109→        }
110→    }
111→
112→    @Published var includePausedInSummary: Bool {
113→        didSet {
114→            defaults.set(includePausedInSummary, forKey: Keys.includePausedInSummary)
115→        }
116→    }
117→
118→    @Published var themeModeRaw: String {
119→        didSet {
120→            let normalized = Self.normalizeThemeMode(themeModeRaw)
121→            if normalized != themeModeRaw {
122→                themeModeRaw = normalized
123→                return
124→            }
125→            defaults.set(normalized, forKey: Keys.themeMode)
126→        }
127→    }
128→
129→    @Published var themeColorRaw: String {
130→        didSet {
131→            let normalized = Self.normalizeThemeColor(themeColorRaw)
132→            if normalized != themeColorRaw {
133→                themeColorRaw = normalized
134→                return
135→            }
136→            defaults.set(normalized, forKey: Keys.themeColor)
137→        }
138→    }
139→
140→    @Published var notifyBeforeBilling: Bool {
141→        didSet {
142→            defaults.set(notifyBeforeBilling, forKey: Keys.notifyBeforeBilling)
143→        }
144→    }
145→
146→    private let defaults: UserDefaults
147→
148→    init(defaults: UserDefaults = .standard) {
149→        self.defaults = defaults
150→
151→        let currency = defaults.string(forKey: Keys.defaultCurrency) ?? "JPY"
152→        self.defaultCurrency = Self.normalizeCurrency(currency)
153→
154→        let rawPast = defaults.object(forKey: Keys.pastMonths) as? Int ?? 6
155→        self.pastMonths = max(1, min(24, rawPast))
156→
157→        let rawFuture = defaults.object(forKey: Keys.futureMonths) as? Int ?? 12
158→        self.futureMonths = max(1, min(36, rawFuture))
159→
160→        self.includePausedInSummary = defaults.object(forKey: Keys.includePausedInSummary) as? Bool ?? false
161→
162→        let rawThemeMode = defaults.string(forKey: Keys.themeMode) ?? ThemeMode.system.rawValue
163→        self.themeModeRaw = Self.normalizeThemeMode(rawThemeMode)
164→
165→        let rawThemeColor = defaults.string(forKey: Keys.themeColor) ?? ThemeColorOption.blue.rawValue
166→        self.themeColorRaw = Self.normalizeThemeColor(rawThemeColor)
167→
168→        self.notifyBeforeBilling = defaults.object(forKey: Keys.notifyBeforeBilling) as? Bool ?? true
169→    }
170→
171→    func resetToDefaults() {
172→        defaults.removeObject(forKey: Keys.defaultCurrency)
173→        defaults.removeObject(forKey: Keys.pastMonths)
174→        defaults.removeObject(forKey: Keys.futureMonths)
175→        defaults.removeObject(forKey: Keys.includePausedInSummary)
176→        defaults.removeObject(forKey: Keys.themeMode)
177→        defaults.removeObject(forKey: Keys.themeColor)
178→        defaults.removeObject(forKey: Keys.notifyBeforeBilling)
179→
180→        defaultCurrency = "JPY"
181→        pastMonths = 6
182→        futureMonths = 12
