Button(String(localized: "auth.account.delete_account"), role: .destructive) {
    isDeleting = true
    Task {
        await authStore.deleteAccount(modelContext: modelContext, settings: settings)
        isDeleting = false
        if authStore.currentUser == nil {
            dismiss()  // AccountView を閉じる
        }
    }
}
```

#### **ステップ4: 削除後の遷移**
```swift
// AppFlowView で自動的にルート画面を切り替え
Group {
    if authStore.currentUser == nil {
        AuthGateView()  // ログイン画面に戻る
    } else {
        RootTabView()
    }
}
.animation(.easeInOut(duration: 0.2), value: authStore.currentUser)
```

